revision.text:
{{ Ambox {{
  #if: {{{type|}}}
  | {{!}} type={{{type}}}
}}{{
  #if: {{{image|}}}
  | {{!}} image={{{image}}}
}}{{
  #if: {{{imageright|}}}
  | {{!}} imageright={{{imageright}}}
}}{{
  #if: {{{style|}}}
  | {{!}} style={{{style}}}
}}{{
  #if: {{{text|}}}
  | {{!}} text={{{text}}}
}}}}<noinclude>
{{Documentation, template}}
</noinclude>

{{#ifeq:{{{small|}}}|yes
| {{tmbox/core
  | small = yes
  | type  = {{{type|}}}
  | image = {{#if:{{{smallimage|}}}| {{{smallimage}}} | {{{image|}}} }}
  | imageright = 
    {{#ifeq:{{{smallimageright|}}}|none
    |    <!-- Don't show any right image -->
    | {{#if:{{{smallimageright|}}}
      | {{{smallimageright}}} 
      | {{{imageright|}}} 
      }}
    }}
  | style = {{{style|}}}
  | textstyle = {{{textstyle|}}}
  | text  = {{#if:{{{smalltext|}}}| {{{smalltext}}} | {{{text}}} }}
  }}
| {{tmbox/core
  | type  = {{{type|}}}
  | image = {{{image|}}}
  | imageright = {{{imageright|}}} 
  | style = {{{style|}}}
  | textstyle = {{{textstyle|}}}
  | text  = {{{text}}}
  }}
}}

